typedef struct Node {
 int data;
 struct Node* next;
} Node;

Node* concatenate(Node* head1, Node* head2) {
 if (head1 == NULL) {
 return head2;
 }
 Node* current = head1;
 while (current->next != NULL) {
 current = current->next;
 }
 current->next = head2;
 return head1;
}

// Example usage:
int main() {
 Node* list1 = (Node*)malloc(sizeof(Node));
 list1->data = 1;
 list1->next = (Node*)malloc(sizeof(Node));
 list1->next->data = 2;
 list1->next->next = (Node*)malloc(sizeof(Node));
 list1->next->next->data = 3;
 list1->next->next->next = NULL;

 Node* list2 = (Node*)malloc(sizeof(Node));
 list2->data = 4;
 list2->next = (Node*)malloc(sizeof(Node));
 list2->next->data = 5;
 list2->next->next = (Node*)malloc(sizeof(Node));
 list2->next->next->data = 6;
 list2->next->next->next = NULL;

 Node* result = concatenate(list1, list2);
 while (result != NULL) {
 printf("%d ", result->data);
 result = result->next;
 }
 return 0;
}
